checker_dsl:
EXISTS (`formatting call FC`, `format string FS`) {
  AND {
    (`FC is a Call`),
    OR {
      (`FC's callee is a FormatMethod`),
      EXISTS (`callable C`, `integer FMTIX`, `FmtSyntax SYNTAX`) {
        AND {
          (`C has a parameter at index FMTIX with String type`),
          (`C has a parameter at index FMTIX+1 with Object[] type`),
          (`C has exactly FMTIX+2 parameters`),
          EXISTS (`call FMT_CALL`) {
            AND {
              (`FMT_CALL is inside callable C`),
              OR {
                EXISTS (`integer I`) {
                  AND {
                    (`formatWrapper(FMT_CALL's callee, I, SYNTAX) holds`),
                    (`getArgumentOrQualifier(FMT_CALL, I) is an access to C's parameter at index FMTIX`),
                    (`FMT_CALL's argument at index I+1 is an access to C's parameter at index FMTIX+1`)
                  }
                },
                EXISTS (`integer I`) {
                  AND {
                    (`FMT_CALL's callee is a StringFormatMethod`),
                    (`FMT_CALL's callee's getFormatStringIndex() = I`),
                    (`SYNTAX = TFmtPrintf()`),
                    (`getArgumentOrQualifier(FMT_CALL, I) is an access to C's parameter at index FMTIX`),
                    (`FMT_CALL's argument at index I+1 is an access to C's parameter at index FMTIX+1`)
                  }
                },
                EXISTS (`integer I`) {
                  AND {
                    (`FMT_CALL's callee is a LoggerFormatMethod`),
                    (`FMT_CALL's callee's getFormatStringIndex() = I`),
                    (`SYNTAX = TFmtLogger()`),
                    (`getArgumentOrQualifier(FMT_CALL, I) is an access to C's parameter at index FMTIX`),
                    (`FMT_CALL's argument at index I+1 is an access to C's parameter at index FMTIX+1`)
                  }
                }
              }
            }
          }
        }
      }
    },
    (`FS is associated with FC as a format string`),
    EXISTS (`integer REFS`, `integer ARGS`) {
      AND {
        (`REFS = FS's maximum format specifier index`),
        (`ARGS = FC's varargs count`),
        (`REFS > ARGS`)
      }
    }
  }
}
